content.code:
# if və else nümunəsi
age = 16
if age >= 18:
    print('Siz yetkin yaşdasınız!')
else:
    print('Siz yetkin yaşda deyilsiniz!')

# if, elif, else nümunəsi
score = 85
if score >= 90:
    print('Əla!')
elif score >= 70:
    print('Yaxşı!')
elif score >= 50:
    print('Kafi!')
else:
    print('Kəsildiniz!')

# Daxili şərtlər
age = 20
has_permission = True

if age >= 18:
    if has_permission:
        print('Sizə icazə verilir!')
    else:
        print('İcazəniz yoxdur!')
else:
    print('Yetkin yaşda deyilsiniz!')

// JavaScript kodu
let age = 20;
let status = age >= 18 ? 'Yetkin' : 'Yetkin deyil';
console.log(status);

# Səhv idarəetməsi
score = '90'
try:
    score = int(score)
    if score >= 50:
        print('Kafi!')
    else:
        print('Kəsildiniz!')
except ValueError:
    print('Xəta: Bal rəqəm olmalıdır!')

# Sadə yoxlama sistemi
temperature = 25
if temperature > 30:
    print('Çox isti!')
elif temperature > 20:
    print('İsti!')
elif temperature > 10:
    print('Sərin!')
else:
    print('Soyuq!')

# if and else example
age = 16
if age >= 18:
    print('You are an adult!')
else:
    print('You are not an adult!')

# if, elif, else example
score = 85
if score >= 90:
    print('Excellent!')
elif score >= 70:
    print('Good!')
elif score >= 50:
    print('Pass!')
else:
    print('Fail!')

# Nested conditions
age = 20
has_permission = True

if age >= 18:
    if has_permission:
        print('Access granted!')
    else:
        print('No permission!')
else:
    print('Not an adult!')

// JavaScript code
let age = 20;
let status = age >= 18 ? 'Adult' : 'Not adult';
console.log(status);

# Error handling
score = '90'
try:
    score = int(score)
    if score >= 50:
        print('Pass!')
    else:
        print('Fail!')
except ValueError:
    print('Error: Score must be a number!')

# Simple validation system
temperature = 25
if temperature > 30:
    print('Very hot!')
elif temperature > 20:
    print('Warm!')
elif temperature > 10:
    print('Cool!')
else:
    print('Cold!')

# Пример if и else
age = 16
if age >= 18:
    print('Вы взрослый!')
else:
    print('Вы не взрослый!')

# Пример if, elif, else
score = 85
if score >= 90:
    print('Отлично!')
elif score >= 70:
    print('Хорошо!')
elif score >= 50:
    print('Удовлетворительно!')
else:
    print('Не сдали!')

# Вложенные условия
age = 20
has_permission = True

if age >= 18:
    if has_permission:
        print('Доступ разрешен!')
    else:
        print('Нет разрешения!')
else:
    print('Не взрослый!')

// Код JavaScript
let age = 20;
let status = age >= 18 ? 'Взрослый' : 'Не взрослый';
console.log(status);

# Обработка ошибок
score = '90'
try:
    score = int(score)
    if score >= 50:
        print('Удовлетворительно!')
    else:
        print('Не сдали!')
except ValueError:
    print('Ошибка: Балл должен быть числом!')

# Простая система проверки
temperature = 25
if temperature > 30:
    print('Очень жарко!')
elif temperature > 20:
    print('Тепло!')
elif temperature > 10:
    print('Прохладно!')
else:
    print('Холодно!')
